use anyhow::Result;
use clap::Parser;

use crate::gateway::Gateway;
use crate::store::SessionStore;

#[derive(Debug, Parser)]
struct Args {
    #[arg(long, default_value = ".")]
    root: std::path::PathBuf,
    #[arg(long, default_value = "127.0.0.1:8787")]
    api_addr: std::net::SocketAddr,
