async fn main() -> Result<()> {
    let args = Args::parse();
    let store = SessionStore::new(session_summary(&args));
    let gateway = Gateway::new(store.clone());
    serve_api(args.api_addr, store.clone()).await?;
    gateway.serve_stdio().await?;
    store.persist_on_shutdown().await?;
    Ok(())
}
